import{_ as t,o,c as u,ag as q}from"./chunks/framework.DvSl3FxN.js";const c=JSON.parse('{"title":"第一章：长安夜","description":"","frontmatter":{"title":"第一章：长安夜","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/chapters/01.md","filePath":"novels/jin-gu-yao/chapters/01.md","lastUpdated":1773897450000}'),e={name:"novels/jin-gu-yao/chapters/01.md"};function a(r,p,s,n,_,i){return o(),u("div",null,[...p[0]||(p[0]=[q('<h1 id="第一章-长安夜" tabindex="-1">第一章：长安夜 <a class="header-anchor" href="#第一章-长安夜" aria-label="Permalink to &quot;第一章：长安夜&quot;">​</a></h1><p>大业十三年，五月十五。</p><p>三娘觉得自己这辈子缝过最久的一件袍子，大概就是柴绍这件了。</p><p>去年秋天猎鹿的时候剐的，左肩一道口子，不长，三寸。柴绍回来的时候浑身是泥，兴高采烈地把一只瘸了腿的兔子往她面前一放——&quot;三娘你看！&quot;三娘看了看兔子，又看了看他肩膀上的口子，说：&quot;你去猎鹿，猎回来一只兔子。兔子还是瘸的。&quot;</p><p>柴绍不以为意：&quot;鹿跑了，但这兔子肥啊。&quot;</p><p>那件袍子就这么搁了大半年。不是没时间缝，是每次拿起来都会想到那只瘸腿兔子，然后就笑，一笑就缝不直，索性放下。</p><p>今天终于又拿起来了，主要是因为——实在没别的事干。</p><p>院子里闹得很。</p><p>&quot;娘——！哥哥又抢我的木马！&quot;</p><p>柴令武——三娘的小儿子，今年三岁，嗓门大得像他爹，肺活量大得像他娘。他站在院子中间，鼻涕糊了半张脸，手里攥着半截木马的尾巴。另半截木马在他哥哥柴哲威手上。</p><p>柴哲威今年五岁，比弟弟高半个头，脸上的表情是一种让三娘非常熟悉的东西——柴绍每次闯了祸装无辜时的表情。</p><p>&quot;我没抢。&quot;柴哲威说，&quot;它自己断的。&quot;</p><p>&quot;你拽断的！&quot;</p><p>&quot;它本来就要断了。&quot;</p><p>三娘头也不抬：&quot;哲威，把马还给弟弟。&quot;</p><p>&quot;可是——&quot;</p><p>&quot;还。&quot;</p><p>柴哲威把半截木马往弟弟怀里一塞，嘟囔了一句什么，大约是&quot;反正也骑不了了&quot;。柴令武接过去，看了看手里的半截马身和半截马尾，愣了三秒，然后嚎啕大哭。</p><p>马三宝从厨房探出头来：&quot;怎么了怎么了？&quot;</p><p>&quot;木马断了。&quot;三娘说。</p><p>&quot;噢。&quot;马三宝看了看哭得惊天动地的小公子，又看了看假装无事发生正在踢墙角蚂蚁的大公子，做出了一个精准的判断：&quot;大公子干的？&quot;</p><p>柴哲威踢蚂蚁的脚顿了一下。</p><p>&quot;三宝，&quot;三娘说。</p><p>马三宝应声就动了——比府里任何仆人都快半拍。不是因为机灵，是因为他认这个声音。十二年了，这个声音叫他&quot;三宝&quot;的时候带着一种别人没有的东西。不是命令，是确认——确认他在，确认他有名字。</p><p>&quot;你去找块木头，给令武重新削一个。&quot;</p><p>&quot;夫人，我上次削的那个，您说像老鼠。&quot;</p><p>&quot;那这次削好看点。&quot;</p><p>&quot;……我尽量。&quot;</p><p>马三宝缩回厨房。三娘听到里面传来翻箱倒柜的声音，然后是一声闷响，然后是马三宝的&quot;哎哟&quot;。</p><p>三娘叹了口气，继续缝袍子。</p><p>这就是大业十三年五月十五日傍晚的柴府。一个女人在缝一件缝了大半年的袍子，一个仆人在厨房里跟木头搏斗，两个小孩，一个在哭，一个在踢蚂蚁。</p><p>长安城一百零九坊，大概有一万个院子在上演差不多的戏码。</p><p>日子就这么过呗，还能怎样。</p><hr><p>柴绍回来的时候，三娘正在给柴令武擦鼻涕。</p><p>小的那个哭累了，趴在三娘腿上睡着了，鼻涕泡还挂在嘴边，一鼓一鼓的。大的那个不知从哪找了根竹竿，在院子里&quot;杀敌&quot;，嘴里&quot;嘿嘿哈哈&quot;地配音，把槐树的花打了一地。</p><p>三娘听到门响，以为是马三宝，没抬头。</p><p>&quot;三娘。&quot;</p><p>她愣了一下。这声音不对——不是马三宝的碎嘴，是柴绍。但柴绍今天不该回来这么早。而且他叫她名字的语气也不对，平时都是大大咧咧的&quot;三娘我回来了！&quot;，今天的声音压得很低，像怕惊醒什么。</p><p>她抬起头。</p><p>柴绍站在门口，穿着当值的袍服，腰间横刀没解，脸上的表情——</p><p>三娘见过柴绍很多种表情。高兴的（猎到东西的时候），心虚的（打碎她茶碗的时候），紧张的（她怀令武临产那天），以及装傻的（大部分时候）。</p><p>但今天这个表情她没见过。</p><p>怎么说呢，像一个人同时踩到了金子和蛇。</p><p>&quot;孩子们……&quot;柴绍看了看睡着的小儿子和正在大战槐树的大儿子。</p><p>三娘秒懂。她把柴令武放到旁边的竹榻上，给他盖了件薄衫，然后对院子里喊：&quot;哲威，带弟弟去找三宝玩。&quot;</p><p>&quot;弟弟睡着了呀。&quot;</p><p>&quot;那你自己去。&quot;</p><p>&quot;我不想去，三宝削的木马好丑——&quot;</p><p>&quot;柴哲威。&quot;</p><p>五岁的柴哲威在母亲的语气里精准地识别出了&quot;再说一个字试试&quot;的信号，竹竿一扔，跑了。</p><p>院子安静下来。槐花还在落。</p><p>柴绍从怀里掏出一截竹管。</p><p>三娘认得那个竹管上的刻字——&quot;渊&quot;。父亲的信。</p><p>她伸手接过来。指尖碰到柴绍的手时，感觉到他的手在抖。不是冷的那种抖，是肾上腺素的那种。</p><p>三娘挑开蜡封，抽出绢帛，看了两遍。</p><p>字不多。意思很明确：起兵。速来。</p><p>她把绢帛折好，抬头看柴绍。</p><p>柴绍等着她说话。他的眼神像一只等着主人扔球的大狗——焦急、期待、又有点不确定自己该往哪跑。</p><p>&quot;你看完了？&quot;</p><p>&quot;嗯。&quot;</p><p>&quot;那——&quot;</p><p>&quot;父亲要起兵，&quot;三娘说，声音不大，&quot;他让你去太原。&quot;</p><p>停顿。</p><p>远处柴哲威的声音飘过来：&quot;三宝——你在削什么？好丑啊！&quot;马三宝的声音：&quot;你行你来！&quot;</p><p>柴绍深吸一口气：&quot;三娘，我得走。可是——&quot;</p><p>他搓了搓手。柴绍搓手是紧张的标志，就像他挠后脑勺是心虚的标志一样，三娘早就摸透了。</p><p>&quot;一起走不行。路远，两个孩子还小，目标太大。可我自己走了，你们留在长安……&quot;他看了看竹榻上睡着的小儿子，声音低了下去，&quot;万一隋兵来查……&quot;</p><p>三娘等他说完。</p><p>柴绍确实说完了。他站在那里，一脸&quot;我知道怎么选都不对但我实在想不出更好的办法&quot;的表情。三娘觉得他这个样子既让人心疼又让人想笑——堂堂千牛备身，能在猎场上一箭射穿奔鹿的男人，面对妻子和孩子的安危时，笨得像块石头。</p><p>&quot;你走吧，&quot;三娘说。</p><p>柴绍愣了。</p><p>&quot;我是个妇人，带着两个孩子，遇事容易找地方躲。&quot;她说到这里，嘴角弯了一下，&quot;再说了，谁会觉得一个带娃的妇人能翻出什么浪来？&quot;</p><p>柴绍盯着她看了好一会儿。</p><p>&quot;三娘……你是不是已经想好了？&quot;</p><p>三娘没有正面回答。她低头看了看手里那件缝了大半年的旧袍，忽然笑了一下。</p><p>&quot;这件袍子我先不缝了。等你回来再说。&quot;</p><p>这句话后来柴绍想了很久。他觉得三娘是在说一件很重要的事——但具体是什么，他想不明白。</p><p>男人嘛。</p><hr><p>柴绍是半夜走的。</p><p>他走之前做了一件让三娘意外的事——去了两个儿子的房间，站在门口看了很久。没进去，怕吵醒他们。</p><p>三娘站在走廊另一头，看着他的背影。</p><p>灯光把柴绍的影子拉得很长。他的肩膀很宽，是常年拉弓的人才有的那种宽。三娘忽然想到一件事：如果柴绍今晚走了，下次见面不知道是什么时候。也不知道还能不能见面。</p><p>她走过去，把一个包袱塞到柴绍手里。</p><p>&quot;什么？&quot;</p><p>&quot;干粮。肉脯。还有令武前天画的画，他说要给爹爹看。&quot;</p><p>柴绍打开包袱看了一眼。里面确实有一张皱巴巴的纸，上面用炭笔画了四个圈，大的两个小的两个，旁边歪歪扭扭写了个&quot;家&quot;字——这是三娘教令武写的第一个字。</p><p>柴绍的鼻子酸了一下。他不是个感性的人，但这一下没绷住。</p><p>&quot;三娘。&quot;</p><p>&quot;嗯。&quot;</p><p>&quot;……我会回来的。&quot;</p><p>&quot;我知道。&quot;三娘帮他把包袱系好，&quot;路上别逞强。遇到隋军的巡逻绕着走。你那个脾气，别看到不平事就冲上去——现在不是当侠客的时候。&quot;</p><p>柴绍嘿嘿一笑。这个笑容三娘太熟悉了——典型的柴绍式笑容，憨，但可靠。</p><p>&quot;那孩子们——&quot;</p><p>&quot;孩子们有我。&quot;</p><p>四个字。轻飘飘的。但柴绍听出了分量。</p><p>他不再说什么了，转身出了角门。夜色把他吞了进去。脚步声越来越远，越来越远，最后消失在坊墙的另一边。</p><p>三娘站在门口，没有关门。夜风吹进来，带着槐花的气味。远处传来更夫的梆子声，慢悠悠的，一下一下。</p><p>她站了很久。</p><p>然后她关上门，回到屋里，把那件旧袍叠好，放进柜子最里面。</p><p>&quot;三宝。&quot;</p><p>黑暗里传来马三宝的声音，带着鼻音——他其实一直没睡，蹲在廊下听着呢。</p><p>&quot;在。&quot;</p><p>&quot;明天一早，把我那套男装找出来。深色的。&quot;</p><p>沉默了两秒。</p><p>&quot;……夫人？&quot;</p><p>&quot;以后别叫夫人了。&quot;三娘的声音很轻，但很清楚。&quot;叫我李公子。&quot;</p><p>又是两秒沉默。</p><p>&quot;那……两位小公子呢？&quot;</p><p>三娘顿了一下。</p><p>这个问题她想过。带着两个孩子上路是最大的变数——三岁和五岁，一个爱哭一个爱闹，走不快藏不住，还动不动要吃要喝要尿。但她不可能把他们留在长安。柴府迟早会被盯上。</p><p>&quot;一起走。&quot;她说，&quot;告诉哲威，跟娘亲去鄠县外婆家住。&quot;</p><p>&quot;那令武呢？他才三岁，路上——&quot;</p><p>&quot;令武不用告诉。三岁的孩子，你把他扛在肩上他就以为在玩。&quot;</p><p>马三宝想了想，发现这话有道理。柴令武确实是那种被扛着跑也能咯咯笑的孩子。</p><p>&quot;那我们什么时候走？&quot;</p><p>&quot;后天。天不亮就走。&quot;</p><p>&quot;带多少人？&quot;</p><p>&quot;七个。加上我们三个大人两个孩子，十二个人。再多就招眼了。&quot;</p><p>马三宝在黑暗中点了点头，虽然三娘看不见。</p><p>&quot;三宝。&quot;</p><p>&quot;嗯？&quot;</p><p>&quot;你怕吗？&quot;</p><p>马三宝想了想，老实回答：&quot;怕。&quot;</p><p>&quot;那还跟着？&quot;</p><p>&quot;夫人——公子让我跟，我就跟。&quot;他顿了顿，补了一句，&quot;再说了，我要是不跟，两位小公子路上谁管？您又不会削木马。&quot;</p><p>三娘在黑暗中笑出了声。这是今天晚上她第一次笑。</p><p>&quot;行了，去睡吧。明天有得忙。&quot;</p><hr><p>五月十八日，寅时。天还黑着。</p><p>三娘换好男装，在铜镜前端详了自己一会儿。镜子里的人像个清瘦的少年，眉骨高，下颌线利落——但腰上鼓了一块，那是令武的小布老虎，三娘随手塞进去的，怕路上他闹。</p><p>她把镜子翻过去，扣在桌上。</p><p>院子里，马三宝正在跟两个孩子搏斗。</p><p>柴哲威倒是乖，背着个小包袱站在那里，一脸严肃，像个出征的小将军。问题是柴令武——这位三岁的小爷被从被窝里薅出来，正处于&quot;半梦半醒且暴怒&quot;的状态，骑在马三宝脖子上，一边揉眼睛一边拽马三宝的头发。</p><p>&quot;疼疼疼——小公子您轻点——&quot;</p><p>&quot;要骑马——&quot;</p><p>&quot;这不是马这是我——哎哟！&quot;</p><p>三娘走过来，从马三宝脖子上把令武抱下来。小家伙迷迷糊糊地搂住三娘的脖子，把脸埋进她肩窝里，嘟囔了一句&quot;爹爹呢&quot;，然后又睡着了。</p><p>三娘拍了拍他的背。</p><p>&quot;走吧。&quot;她说。</p><p>一行人从角门鱼贯而出。七个仆从，两匹马，三个大人，两个小孩。天边还没有一丝光，巷子里安静得只听见脚步声和柴令武均匀的呼吸。</p><p>柴哲威走在三娘旁边，仰头看了看她的男装。</p><p>&quot;娘，&quot;他压低声音，大概觉得自己在执行秘密任务，&quot;你穿成这样，不像男人。&quot;</p><p>三娘低头看他：&quot;哪里不像？&quot;</p><p>柴哲威想了想：&quot;男人不会走路这么好看。&quot;</p><p>马三宝在后面差点被自己的口水呛到。</p><p>三娘没理他们，加快了脚步。</p><p>长安还在沉睡。再过两刻钟坊门就要开了。</p><p>城南的天际线上，有一条极细极淡的光。</p><p>大业十三年的天，快要亮了。</p><p>而三娘怀里的柴令武翻了个身，把口水流到了她肩膀上。</p><hr><p>同一个时辰。鄠县。</p><p>县衙后堂的灯还亮着。</p><p>一个中年人坐在案后，面前摊着一封公文。公文上的火漆是长安留守的——红色，压得很重，说明是加急。</p><p>公文不长。意思很明确：太原李渊反迹已显，其婿柴绍已失踪。速查李氏在鄠县产业、人员动向，有异立报。</p><p>中年人把公文看了两遍。然后他把灯芯拨亮了一点，从抽屉里取出一张旧图——鄠县及周边的庄园分布图。他的手指在图上慢慢移动，最后停在终南山脚下的一个位置。</p><p>李氏庄园。</p><p>他把那个位置用指甲掐了一道印子。然后把公文折好，锁进了柜子里。</p><p>灯光照着他的脸。不年轻了，但眼睛很亮——那种在乱世里选对了赌注的人才会有的亮。</p><hr><p><em>（第一章终）</em></p>',163)])])}const d=t(e,[["render",a]]);export{c as __pageData,d as default};
